import { fromOpenai } from '@instructor-ai/instructor';
import { OpenAI } from 'openai';
import { vex } from 'vex-sdk';

import { z } from 'zod';

const FOIARequest = z.object({
  requester: z.string(),
  topic: z.string(),
  sensitivity: z.enum(['UNCLASSIFIED', 'CLASSIFIED', 'TOP_SECRET']),
});

const client = fromOpenai(new OpenAI());

const extractFOIA = vex.verify(
  async (prompt: string) => {
    const response = await client.chat.completions.create({
      model: 'gpt-4o',
      responseModel: FOIARequest,
      messages: [{ role: 'user', content: prompt }],
    });
    return response;
  },
  { metric: 'foia-classification' }
);

const result = await extractFOIA('FOIA request about drone operations');
console.log(result);

from instructor import Instructor
from pydantic import BaseModel
from typing import List
import vex

class RegionalImpact(BaseModel):
    state: str
    population_affected: int

class PolicyImpact(BaseModel):
    policy_name: str
    regions: List[RegionalImpact]

client = Instructor.from_openai(OpenAI())

@vex.verify(metric="policy-impact", max_retries=3)
def assess_impact(prompt: str) -> PolicyImpact:
    return client.chat.completions.create(
        model="gpt-4o",
        response_model=PolicyImpact,
        messages=[{"role": "user", "content": prompt}]
    )

impact = assess_impact("Impact of new tax policy on CA and NY")
print(impact.model_dump_json(indent=2))
